 * Credential state for one send direction. `Pending` means a rotation commit
 * was sent but the opposing side has not yet committed their half.
 */

public enum AgentState: Equatable, Hashable {
    
    case sync(clientId: ClientId
    )
    case pending(old: ClientId, new: ClientId
    )





}

#if compiler(>=6)
extension AgentState: Sendable {}
#endif

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeAgentState: FfiConverterRustBuffer {
    typealias SwiftType = AgentState

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> AgentState {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .sync(clientId: try FfiConverterTypeClientId.read(from: &buf)
        )
        
        case 2: return .pending(old: try FfiConverterTypeClientId.read(from: &buf), new: try FfiConverterTypeClientId.read(from: &buf)
        )
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: AgentState, into buf: inout [UInt8]) {
        switch value {
        
        
        case let .sync(clientId):
            writeInt(&buf, Int32(1))
            FfiConverterTypeClientId.write(clientId, into: &buf)
            
        
        case let .pending(old,new):
            writeInt(&buf, Int32(2))
            FfiConverterTypeClientId.write(old, into: &buf)
            FfiConverterTypeClientId.write(new, into: &buf)
            
        }
    }
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
