    return try FfiConverterTypeAgentState.lift(buf)
}

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public func FfiConverterTypeAgentState_lower(_ value: AgentState) -> RustBuffer {
    return FfiConverterTypeAgentState.lower(value)
}



public enum TwoMlsPqError: Swift.Error, Equatable, Hashable, Foundation.LocalizedError {

    
    
    case Mls
    case InvalidKeyPackage
    case MissingWelcome
    case PskBinding
    case PqNotAvailable
    case SessionNotEstablished
    case SessionNotReady
    case ProposalRejected
    case DecryptionFailed
    case ArchiveInvalid

    

    

    
    public var errorDescription: String? {
        String(reflecting: self)
    }
    
}

#if compiler(>=6)
extension TwoMlsPqError: Sendable {}
#endif

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeTwoMlsPqError: FfiConverterRustBuffer {
    typealias SwiftType = TwoMlsPqError

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> TwoMlsPqError {
        let variant: Int32 = try readInt(&buf)
        switch variant {

        

        
        case 1: return .Mls
        case 2: return .InvalidKeyPackage
        case 3: return .MissingWelcome
        case 4: return .PskBinding
        case 5: return .PqNotAvailable
        case 6: return .SessionNotEstablished
        case 7: return .SessionNotReady
        case 8: return .ProposalRejected
        case 9: return .DecryptionFailed
        case 10: return .ArchiveInvalid

         default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: TwoMlsPqError, into buf: inout [UInt8]) {
        switch value {

        

        
        
        case .Mls:
            writeInt(&buf, Int32(1))
        
        
        case .InvalidKeyPackage:
            writeInt(&buf, Int32(2))
        
        
        case .MissingWelcome:
            writeInt(&buf, Int32(3))
        
        
        case .PskBinding:
            writeInt(&buf, Int32(4))
        
        
        case .PqNotAvailable:
            writeInt(&buf, Int32(5))
        
        
        case .SessionNotEstablished:
            writeInt(&buf, Int32(6))
        
        
        case .SessionNotReady:
            writeInt(&buf, Int32(7))
        
        
        case .ProposalRejected:
            writeInt(&buf, Int32(8))
        
        
        case .DecryptionFailed:
            writeInt(&buf, Int32(9))
        
        
        case .ArchiveInvalid:
            writeInt(&buf, Int32(10))
        
        }
    }
}


